{
  "compilerOptions": {
    "experimentalDecorators": true,
    "emitDecoratorMetadata": true
  }
}

// Sinif dekoratoru
function sealed(constructor: Function) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

@sealed
class Person {
  name: string;
  constructor(name: string) {
    this.name = name;
  }
  greet(): string {
    return `Hello, ${this.name}!`;
  }
}

const person = new Person('Alice');
console.log(person.greet()); // Hello, Alice!

// Metod dekoratoru
function logMethod(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    console.log(`Calling ${propertyKey} with arguments: ${args}`);
    return originalMethod.apply(this, args);
  };
}

class Person {
  name: string;
  constructor(name: string) {
    this.name = name;
  }

  @logMethod
  greet(message: string): string {
    return `${message}, ${this.name}!`;
  }
}

const person = new Person('Alice');
console.log(person.greet('Hello')); // Calling greet with arguments: Hello
// Hello, Alice!

// Xüsusiyyət dekoratoru
function readOnly(target: any, propertyKey: string) {
  Object.defineProperty(target, propertyKey, { writable: false });
}

class Person {
  @readOnly
  name: string;

  constructor(name: string) {
    this.name = name;
  }
}

const person = new Person('Alice');
// person.name = 'Bob'; // Xəta: name yalnız oxuna bilər
console.log(person.name); // Alice

// Parametr dekoratoru
function logParameter(target: any, propertyKey: string, parameterIndex: number) {
  console.log(`Parameter at index ${parameterIndex} in ${propertyKey}`);
}

class Person {
  greet(@logParameter message: string): string {
    return `Hello, ${message}!`;
  }
}

const person = new Person();
person.greet('Alice'); // Parameter at index 0 in greet
// Hello, Alice!

// TypeScript dekoratoru
function logClass(constructor: Function) {
  console.log(`Created class: ${constructor.name}`);
}

@logClass
class Person {
  constructor(public name: string) {}
}

const person = new Person('Alice'); // Created class: Person

// Tip təhlükəsizliyi ilə dekorator
function validateString(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (value: string) {
    if (typeof value !== 'string') {
      throw new Error('Argument must be a string');
    }
    return originalMethod.apply(this, [value]);
  };
}

class Person {
  @validateString
  greet(name: string): string {
    return `Hello, ${name}!`;
  }
}

const person = new Person();
console.log(person.greet('Alice')); // Hello, Alice!
// person.greet(123); // Xəta: Argument must be a string

// Səhvə yol açan dekorator istifadəsi
function restrictAccess(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  descriptor.value = function () {
    throw new Error('Access restricted');
  };
}

class Person {
  @restrictAccess
  greet(name: string): string {
    return `Hello, ${name}!`;
  }
}

const person = new Person();
// console.log(person.greet('Alice')); // Xəta: Access restricted

// Real layihə ssenarisi
function logExecutionTime(target: any, propertyKey: string, descriptor: PropertyDescriptor) {
  const originalMethod = descriptor.value;
  descriptor.value = function (...args: any[]) {
    const start = performance.now();
    const result = originalMethod.apply(this, args);
    const end = performance.now();
    console.log(`${propertyKey} took ${end - start}ms`);
    return result;
  };
}

class Calculator {
  @logExecutionTime
  calculateSum(a: number, b: number): number {
    return a + b;
  }
}

const calc = new Calculator();
console.log(calc.calculateSum(5, 3)); // calculateSum took ...ms
// 8

